function cn(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(" ");
}
import { ButtonHTMLAttributes, forwardRef } from "react";

type Variant = "default" | "ghost" | "outline";
type Size = "default" | "lg";

interface Props extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: Variant;
  size?: Size;
}

export const Button = forwardRef<HTMLButtonElement, Props>(function Button(
  { className, variant = "default", size = "default", ...props },
  ref
) {
  const base =
    "inline-flex items-center justify-center rounded-md font-medium transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-60";
  const variants: Record<Variant, string> = {
    default: "bg-gray-900 text-white hover:opacity-90",
    ghost: "bg-transparent hover:bg-black/5",
    outline: "border border-gray-300 hover:bg-black/5",
  };
  const sizes: Record<Size, string> = {
    default: "px-4 py-2 text-sm",
    lg: "px-8 py-6 text-lg",
  };
  return (
    <button
      ref={ref}
      className={cn(base, variants[variant], sizes[size], className)}
      {...props}
    />
  );
});
